CREATE TABLE flights_sample (
    YEAR INTEGER,
    MONTH INTEGER,
    DAY INTEGER,
    DAY_OF_WEEK INTEGER,
    AIRLINE VARCHAR(255),
    FLIGHT_NUMBER INTEGER,
    TAIL_NUMBER VARCHAR(255),
    ORIGIN_AIRPORT VARCHAR(255),
    DESTINATION_AIRPORT VARCHAR(255),
    SCHEDULED_DEPARTURE INTEGER,
    DEPARTURE_TIME FLOAT,
    DEPARTURE_DELAY FLOAT,
    TAXI_OUT FLOAT,
    WHEELS_OFF FLOAT,
    SCHEDULED_TIME FLOAT,
    ELAPSED_TIME FLOAT,
    AIR_TIME FLOAT,
    DISTANCE INTEGER,
    WHEELS_ON FLOAT,
    TAXI_IN FLOAT,
    SCHEDULED_ARRIVAL INTEGER,
    ARRIVAL_TIME FLOAT,
    ARRIVAL_DELAY FLOAT,
    DIVERTED INTEGER,
    CANCELLED INTEGER,
    CANCELLATION_REASON VARCHAR(255),
    AIR_SYSTEM_DELAY FLOAT,
    SECURITY_DELAY FLOAT,
    AIRLINE_DELAY FLOAT,
    LATE_AIRCRAFT_DELAY FLOAT,
    WEATHER_DELAY FLOAT
);











